use atomic_data::distributed::{AgentStepPayload, TaskAction, WireDecode, WireEncode};
use once_cell::sync::Lazy;
use std::any::TypeId;
use std::collections::HashMap;
use std::sync::OnceLock;

/// Dispatch function generated by the `#[task]` macro: `(action, args, input) -> bytes`.
///
/// The error is a plain `String`, not a typed enum: every `#[task]`-annotated function in
/// every binary that links this crate must match this exact `fn`-pointer signature, so the
/// error type is a fixed part of the macro-generated ABI rather than an internal API choice.
/// `NativeDispatcher::dispatch` converts it into a proper `ComputeError` immediately on
/// return (`runtimes/native.rs`).
pub type TaskHandlerFn = fn(&TaskAction, &[u8], &[u8]) -> Result<Vec<u8>, String>;

/// Shuffle-map write handler: `(data, shuffle_id, map_id, num_reduce, partitioner) -> ()`.
///
/// Same `String`-error rationale as [`TaskHandlerFn`]: this is a `fn`-pointer ABI shared by
/// every `register_shuffle_map!(K, V)` instantiation, converted to `ComputeError` on return.
pub type ShuffleMapHandlerFn = fn(
    &[u8],
    usize,
    usize,
    usize,
    &atomic_data::partitioner::PartitionerSchema,
) -> Result<(), String>;

/// A compiled-in task dispatch entry.
///
/// Every function annotated with `#[task]` submits one of these via
/// `inventory::submit!` at link time. The worker binary collects them all
/// into [`TASK_REGISTRY`] at startup.
pub struct TaskEntry {
    /// Stable identifier for this task, e.g. `"mycrate::mymod::double::a1b2c3d4"`.
    /// Matches the `op_id` field in [`atomic_data::distributed::TaskEnvelope`].
    pub op_id: &'static str,
    /// FNV-1a hash of the function/closure body tokens, computed at compile time.
    /// Used to build [`REGISTRY_FINGERPRINT`] — a single value that captures
    /// the entire task registry state for driver/worker version checking.
    pub body_hash: u64,
    /// The dispatch function generated by the `#[task]` macro.
    pub handler: TaskHandlerFn,
}

inventory::collect!(TaskEntry);

/// Global compile-time task registry — built once at startup from all
/// `inventory::submit!(TaskEntry { ... })` calls linked into the binary.
///
/// Keyed by `op_id`. Workers call `TASK_REGISTRY.get(op_id)` to dispatch.
///
/// Panics at startup if two entries share the same `op_id` AND point to different
/// handler addresses (a sign of a copy-paste error in `#[task(name = "…")]`).
/// Identical handlers for the same `op_id` are silently deduplicated — this is the
/// expected case for two `task_fn!` closures with the same body in the same module.
pub static TASK_REGISTRY: Lazy<HashMap<&'static str, TaskHandlerFn>> = Lazy::new(|| {
    let mut map: HashMap<&'static str, TaskHandlerFn> = HashMap::new();
    for entry in inventory::iter::<TaskEntry> {
        if let Some(&existing) = map.get(entry.op_id) {
            // Two handlers for the same op_id: allow only if they carry the same
            // body_hash (identical task_fn! bodies).  A hash collision here means
            // a copy-paste error in `#[task(name = "…")]`.
            let existing_hash = inventory::iter::<TaskEntry>
                .into_iter()
                .find(|e| e.op_id == entry.op_id)
                .map(|e| e.body_hash)
                .unwrap_or(0);
            if existing_hash != entry.body_hash {
                panic!(
                    "Atomic task registry: duplicate op_id \"{}\" with different bodies.\n\
                         Fix: give each task a unique name.",
                    entry.op_id
                );
            }
            let _ = existing;
        } else {
            map.insert(entry.op_id, entry.handler);
        }
    }
    map
});

/// A single `u64` that fingerprints the entire compiled-in task registry.
///
/// Computed at startup by sorting all `(op_id, body_hash)` pairs and folding
/// them with FNV-1a. Two binaries with identical task implementations produce
/// the same fingerprint even if compiled independently.
///
/// The driver checks this against each worker's advertised fingerprint during
/// registration. A mismatch means the binaries diverged — redeploy workers.
pub static REGISTRY_FINGERPRINT: Lazy<u64> = Lazy::new(|| {
    const FNV_OFFSET: u64 = 14_695_981_039_346_656_037;
    const FNV_PRIME: u64 = 1_099_511_628_211;

    let mut entries: Vec<(&str, u64)> = inventory::iter::<TaskEntry>
        .into_iter()
        .map(|e| (e.op_id, e.body_hash))
        .collect();
    // Sort for determinism — inventory iteration order is not guaranteed.
    entries.sort_unstable_by_key(|(id, _)| *id);

    entries.iter().fold(FNV_OFFSET, |mut h, (id, hash)| {
        for b in id.as_bytes() {
            h ^= *b as u64;
            h = h.wrapping_mul(FNV_PRIME);
        }
        for b in hash.to_le_bytes() {
            h ^= b as u64;
            h = h.wrapping_mul(FNV_PRIME);
        }
        h
    })
});

/// A compile-time shuffle-write handler registered for a specific `(K, V)` type pair.
///
/// Place `register_shuffle_map!(K, V)` in your binary once per pair used with
/// `reduce_by_key` or `group_by_key`. The worker binary collects all entries into
/// [`SHUFFLE_MAP_REGISTRY`] at startup.
///
/// # Handler contract
///
/// `handler(data, shuffle_id, map_partition_id, num_reduce_partitions)`:
/// - `data`: rkyv-encoded `Vec<(K, V)>` from the preceding pipeline ops
/// - Partitions elements by `FxHash(K) % num_reduce_partitions`
/// - Writes each bucket as bincode-encoded `Vec<(K, V)>` to `SHUFFLE_CACHE`
/// - Returns `Ok(())` on success or an error message
pub struct ShuffleMapEntry {
    /// Function pointer that returns the stable dispatch key for this `(K, V)` pair.
    ///
    /// Generated by `register_shuffle_map!(K, V)` as
    /// `concat!(stringify!(K), "::", stringify!(V))` — a compile-time string literal
    /// that is stable across compiler versions (unlike `std::any::type_name`).
    pub type_id: fn() -> &'static str,
    /// The actual write handler.
    pub handler: ShuffleMapHandlerFn,
}

inventory::collect!(ShuffleMapEntry);

/// Global compile-time shuffle-map registry — built once at startup from all
/// `register_shuffle_map!(K, V)` calls linked into the binary.
///
/// Keyed by the stringify-based key (e.g. `"String::u32"`).
/// `NativeBackend` uses this when it sees `StepKind::ShuffleMap`.
pub static SHUFFLE_MAP_REGISTRY: Lazy<HashMap<&'static str, ShuffleMapHandlerFn>> =
    Lazy::new(|| {
        inventory::iter::<ShuffleMapEntry>
            .into_iter()
            .map(|entry| ((entry.type_id)(), entry.handler))
            .collect()
    });

/// A compile-time **sorted** shuffle-write handler for `(K, V)` where `K: Ord`.
///
/// Registered by `register_sort_shuffle_map!(K, V)` (opt-in for ordered keys). When the
/// driver marks a shuffle as a sort-shuffle, the worker uses this handler to sort each
/// reduce-partition bucket by key before writing, so the driver-side reduce can k-way merge
/// sorted runs instead of full-sorting.
pub struct SortShuffleMapEntry {
    /// Stable dispatch key for the `(K, V)` pair (same `"K::V"` string as `ShuffleMapEntry`).
    pub type_id: fn() -> &'static str,
    /// The sorted write handler.
    pub handler: ShuffleMapHandlerFn,
}

inventory::collect!(SortShuffleMapEntry);

/// Global compile-time **sorted** shuffle-map registry. Keyed by the same `"K::V"` string as
/// [`SHUFFLE_MAP_REGISTRY`]; an entry exists only for key types where
/// `register_sort_shuffle_map!(K, V)` was called (i.e. `K: Ord`).
pub static SORT_SHUFFLE_MAP_REGISTRY: Lazy<HashMap<&'static str, ShuffleMapHandlerFn>> =
    Lazy::new(|| {
        inventory::iter::<SortShuffleMapEntry>
            .into_iter()
            .map(|entry| ((entry.type_id)(), entry.handler))
            .collect()
    });

/// A registered state-merge function for distributed stateful streaming.
///
/// Content-agnostic, so the data/compute layers carry no streaming types: it
/// operates on opaque serialized state. The worker calls it for a
/// [`StepKind::MergeState`](atomic_data::distributed::StepKind::MergeState):
/// `prev` is the shard's current serialized state (`None` if this is the first
/// merge), `partials` is this batch's partial state for the shard, and `params` is
/// the merge/emit configuration. It returns `(new_state_bytes, emitted_bytes)`.
///
/// Same `String`-error rationale as [`ShuffleMapHandlerFn`]: this is a `fn`-pointer
/// ABI shared across binaries, converted to `ComputeError` at the dispatch boundary.
pub type StateMergeFn =
    fn(prev: Option<&[u8]>, partials: &[u8], params: &[u8]) -> Result<(Vec<u8>, Vec<u8>), String>;

/// A compile-time state-merge handler, registered by `register_state_merge!`.
pub struct StateMergeEntry {
    /// Stable name used as the dispatch key (e.g. `"atomic_structured::windowed_v1"`).
    pub name: &'static str,
    /// The merge handler.
    pub handler: StateMergeFn,
}

inventory::collect!(StateMergeEntry);

/// Global compile-time state-merge registry — built once from all
/// `register_state_merge!` calls linked into the binary. `NativeBackend` uses this
/// when it sees [`StepKind::MergeState`](atomic_data::distributed::StepKind::MergeState).
pub static STATE_MERGE_REGISTRY: Lazy<HashMap<&'static str, StateMergeFn>> = Lazy::new(|| {
    inventory::iter::<StateMergeEntry>
        .into_iter()
        .map(|entry| (entry.name, entry.handler))
        .collect()
});

/// A compile-time named-partitioner factory, registered by
/// `register_partitioner!(P)` for a `P: NamedPartitioner`.
///
/// Lets distributed `partition_by_named` ship a user partitioner by **name**
/// (no closure serialization): the driver puts the name in the shuffle's
/// `PartitionerSchema::Custom`, and the worker rebuilds the partitioner via this
/// factory — mirroring how `#[task]` ships compute by op_id.
pub struct PartitionerEntry {
    /// The partitioner's stable registry name (`<P as NamedPartitioner>::NAME`).
    pub name: fn() -> &'static str,
    /// Reconstructs the partitioner from its partition count.
    pub factory: PartitionerFactoryFn,
}

inventory::collect!(PartitionerEntry);

/// Reconstructs a registered named partitioner from its partition count.
pub type PartitionerFactoryFn = fn(usize) -> atomic_data::partitioner::Partitioner;

/// Global compile-time named-partitioner registry — built once from all
/// `register_partitioner!(P)` calls linked into the binary. Keyed by `P::NAME`.
pub static PARTITIONER_REGISTRY: Lazy<HashMap<&'static str, PartitionerFactoryFn>> =
    Lazy::new(|| {
        inventory::iter::<PartitionerEntry>
            .into_iter()
            .map(|entry| ((entry.name)(), entry.factory))
            .collect()
    });

/// Reconstruct a registered named partitioner, or `None` if its name was never
/// registered in this binary (the caller then falls back to hash partitioning).
pub fn lookup_partitioner(
    name: &str,
    num_partitions: usize,
) -> Option<atomic_data::partitioner::Partitioner> {
    PARTITIONER_REGISTRY
        .get(name)
        .map(|factory| factory(num_partitions))
}

/// Maps a concrete `(K, V)` `TypeId` to its stable shuffle dispatch key.
///
/// Used by the driver (in `rdd/typed.rs`) to look up the key when building a
/// `ShuffleMap` pipeline op. The key is the same `stringify!`-based string stored
/// in [`SHUFFLE_MAP_REGISTRY`], ensuring driver and worker use an identical lookup.
///
/// Submitted by `register_shuffle_map!(K, V)` alongside [`ShuffleMapEntry`].
pub struct ShuffleKeyEntry {
    /// Returns `TypeId::of::<(K, V)>()` — used as the lookup key by the driver.
    pub type_id: fn() -> TypeId,
    /// The stable dispatch key (e.g. `"String::u32"`).
    pub key: &'static str,
}

inventory::collect!(ShuffleKeyEntry);

/// Global map from `TypeId::of::<(K, V)>()` to the shuffle dispatch key string.
///
/// The driver calls `SHUFFLE_KEY_REGISTRY.get(&TypeId::of::<(K, V)>())` to obtain
/// the key to embed in a `ShuffleMap` pipeline op payload.
pub static SHUFFLE_KEY_REGISTRY: Lazy<HashMap<TypeId, &'static str>> = Lazy::new(|| {
    inventory::iter::<ShuffleKeyEntry>
        .into_iter()
        .map(|entry| ((entry.type_id)(), entry.key))
        .collect()
});

/// Object-safe runner for [`StepKind::AgentStep`] ops.
///
/// `atomic-nlq` provides the concrete implementation and installs it via
/// [`register_agent_runner`] at startup — avoiding a direct `atomic-compute →
/// atomic-nlq` dependency. `NativeDispatcher` looks it up in
/// [`AGENT_RUNNER_REGISTRY`] when it sees an `AgentStep` op.
///
/// `run_partition` is synchronous; the implementation may call
/// `tokio::runtime::Handle::current().block_on(...)` because dispatch always
/// runs inside a `spawn_blocking` closure (see `executor.rs`).
pub trait AgentRunner: Send + Sync {
    /// Execute a multi-round agent loop over partition inputs.
    ///
    /// `inputs` is rkyv-encoded `Vec<String>` (or JSON array fallback for Python/JS).
    /// Returns rkyv-encoded `Vec<AgentFindings>` on success, or an error string.
    fn run_partition(&self, payload: &AgentStepPayload, inputs: &[u8]) -> Result<Vec<u8>, String>;
}

/// Invoke a registered `fn(String) -> String` `#[task]` by its op_id, using the same
/// `TaskAction::Map` wire encoding the macro generates for that signature.
///
/// Used by `agent_step` tool dispatch (`atomic-nlq`'s `TOOL_CALL:` handling) to call a
/// Rust tool by op_id with one JSON-text argument and get one JSON-text result back —
/// the `fn(String) -> String` shape `AgentStepPayload.tool_refs` requires for Rust tools
/// (see `agent-step-tool-calling` design notes: `serde_json::Value` has no rkyv impl, so
/// the wire-level signature must be `String` in/out).
pub fn invoke_str_task(op_id: &str, arg: String) -> Result<String, String> {
    let handler = TASK_REGISTRY
        .get(op_id)
        .ok_or_else(|| format!("tool '{op_id}' is not registered in TASK_REGISTRY"))?;
    let data = vec![arg]
        .encode_wire()
        .map_err(|e| format!("encode tool arg for '{op_id}': {e}"))?;
    let result = handler(&TaskAction::Map, &[], &data)?;
    let mut out = Vec::<String>::decode_wire(&result)
        .map_err(|e| format!("decode tool result for '{op_id}': {e}"))?;
    out.pop()
        .ok_or_else(|| format!("tool '{op_id}' returned no output"))
}

/// Global agent runner registry — populated once by [`register_agent_runner`].
///
/// `None` until `register_agent_runner` is called. If `AgentStep` is dispatched
/// without a registered runner the worker fails with a clear error message.
pub static AGENT_RUNNER_REGISTRY: OnceLock<Box<dyn AgentRunner>> = OnceLock::new();

/// Install `runner` as the global agent runner.
///
/// Idempotent: if called more than once (e.g. from `#[pymodule]` / `#[module]`
/// init that runs multiple times in tests), the second call is silently ignored.
pub fn register_agent_runner(runner: Box<dyn AgentRunner>) {
    let _ = AGENT_RUNNER_REGISTRY.set(runner);
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn task_registry_is_accessible() {
        // Registry may be empty in unit tests (no #[task] functions in this crate),
        // but it must be constructible without panicking.
        let _ = &*TASK_REGISTRY;
    }

    #[test]
    fn task_registry_get_unknown_returns_none() {
        assert!(TASK_REGISTRY.get("nonexistent::op").is_none());
    }
}
